// Extrae el texto y la decisión de escalar de la respuesta de Claude (formato JSON)
const resp = $json;
const ctx = $('Preparar mensajes (EDITA TU PROMPT AQUÍ)').first().json;

let reply = '';
let escalate = false;
let escalationReason = '';

if (resp.stop_reason === 'refusal') {
  reply = 'Disculpá, no puedo ayudarte con eso. ¿Tenés alguna consulta sobre el Combo Biotina?';
  escalate = true;
  escalationReason = 'Respuesta bloqueada por seguridad (refusal)';
} else {
  const textBlock = (resp.content || []).find(b => b.type === 'text');
  const raw = textBlock ? textBlock.text : '';
  try {
    const parsed = JSON.parse(raw);
    reply = (parsed.reply || '').trim();
    escalate = !!parsed.escalate;
    escalationReason = parsed.escalation_reason || '';
  } catch (e) {
    // Si no vino JSON válido, se usa el texto tal cual y se escala para revisión manual
    reply = raw.trim();
    escalate = true;
    escalationReason = 'No se pudo interpretar la respuesta de la IA en el formato esperado';
  }
}

if (!reply) {
  reply = 'Disculpá, ¿podrías repetirme tu consulta?';
}

return [{ json: { ...ctx, reply, escalate, escalationReason } }];

// Genera dos filas para guardar en chat_history
const d = $json;
return [
  { json: { session_id: d.sessionId, role: 'user', content: d.text } },
  { json: { session_id: d.sessionId, role: 'assistant', content: d.reply } }
];

// Deja pasar solo si Claude decidió que hay que escalar
if (!$json.escalate) return [];
return [{ json: $json }];

